# ─── HELPERS ────────────────────────────────────────────────────────────────
def shadow(widget, blur=16, offset=(0, 4), color=(28, 20, 16, 18)):
    eff = QGraphicsDropShadowEffect(widget)
    eff.setBlurRadius(blur)
    eff.setOffset(offset[0], offset[1])
    eff.setColor(QColor(*color))
    widget.setGraphicsEffect(eff)
    return eff


def label(text, size=13, color=C["text"], bold=False, italic=False):
    lbl = QLabel(text)
    f = QFont("Segoe UI", size)
    f.setBold(bold)
    f.setItalic(italic)
    lbl.setFont(f)
    lbl.setStyleSheet(f"color: {color}; background: transparent;")
    return lbl


# ─── TOPBAR ─────────────────────────────────────────────────────────────────
class TopBar(QWidget):
    logout_clicked = pyqtSignal()
    user_clicked   = pyqtSignal()

    def __init__(self, username="vansh", parent=None):
        super().__init__(parent)
        self.username = username
        self.setFixedHeight(64)
        self._build()

    def paintEvent(self, e):
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)
        grad = QLinearGradient(0, 0, self.width(), self.height())
        grad.setColorAt(0.0, QColor(C["red_dark"]))
        grad.setColorAt(0.4, QColor(C["red"]))
        grad.setColorAt(1.0, QColor(C["red_bright"]))
        p.fillRect(self.rect(), QBrush(grad))
        # bottom shadow line
        p.setPen(QPen(QColor(0, 0, 0, 30), 1))
        p.drawLine(0, self.height()-1, self.width(), self.height()-1)

    def _build(self):
        lay = QHBoxLayout(self)
        lay.setContentsMargins(32, 0, 24, 0)
        lay.setSpacing(0)

        # ── LABOMED logo
        labomed = self._labomed_logo()
        lay.addWidget(labomed)

        # divider
        div = QFrame()
        div.setFixedSize(1, 34)
        div.setStyleSheet("background: rgba(255,255,255,0.25);")
        lay.addSpacing(18)
        lay.addWidget(div)
        lay.addSpacing(18)

        # ── Pixel Pro mark
        pixelpro = self._pixelpro_brand()
        lay.addWidget(pixelpro)

        lay.addStretch()

        # ── User pill
        self.user_btn = self._user_pill()
        lay.addWidget(self.user_btn)
        lay.addSpacing(12)

        # ── Power button
        power = self._power_btn()
        lay.addWidget(power)

    def _labomed_logo(self):
        """Render the real LABOMED logo (white, transparent bg) scaled to fit topbar."""
        import base64 as _b64
        lbl = QLabel()
        lbl.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground)
        lbl.setStyleSheet("background: transparent;")
        raw = _b64.b64decode(LABOMED_LOGO_B64)
        pixmap = QPixmap()
        pixmap.loadFromData(raw, "PNG")
        target_h = 44
        scaled = pixmap.scaledToHeight(target_h, Qt.TransformationMode.SmoothTransformation)
        lbl.setPixmap(scaled)
        lbl.setFixedSize(scaled.size())
        return lbl

    def _pixelpro_brand(self):
        w = QWidget()
        w.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground)
        h = QHBoxLayout(w)
        h.setContentsMargins(0, 0, 0, 0)
        h.setSpacing(0)

        name = QLabel("Pixel Pro")
        nf = QFont("Segoe UI", 14, QFont.Weight.DemiBold)
        name.setFont(nf)
        name.setStyleSheet("color: rgba(255,255,255,0.92); background: transparent;")
        h.addWidget(name)
        return w

    def _user_pill(self):
        btn = QPushButton()
        btn.setCursor(QCursor(Qt.CursorShape.PointingHandCursor))
        btn.setFixedHeight(36)

        # avatar + name
        inner = QHBoxLayout(btn)
        inner.setContentsMargins(8, 0, 14, 0)
        inner.setSpacing(8)

        av = QLabel(self.username[0].upper())
        avf = QFont("Segoe UI", 11, QFont.Weight.Bold)
        av.setFont(avf)
        av.setFixedSize(26, 26)
        av.setAlignment(Qt.AlignmentFlag.AlignCenter)
        av.setStyleSheet(
            "background: white; color: #B91C1C; border-radius: 13px;"
        )

        uname = QLabel(self.username)
        uf = QFont("Segoe UI", 12, QFont.Weight.DemiBold)
        uname.setFont(uf)
        uname.setStyleSheet("color: white; background: transparent;")

        inner.addWidget(av)
        inner.addWidget(uname)

        btn.setStyleSheet("""
            QPushButton {
                background: rgba(255,255,255,0.12);
                border: 1px solid rgba(255,255,255,0.22);
                border-radius: 10px;
            }
            QPushButton:hover {
                background: rgba(255,255,255,0.22);
            }
        """)
        btn.clicked.connect(self.user_clicked)
        return btn

    def _power_btn(self):
        btn = QPushButton("⏻")
        btn.setFixedSize(36, 36)
        btn.setCursor(QCursor(Qt.CursorShape.PointingHandCursor))
        btn.setFont(QFont("Segoe UI", 14))
        btn.setStyleSheet("""
            QPushButton {
                background: transparent;
                border: 1px solid transparent;
                border-radius: 9px;
                color: rgba(255,255,255,0.65);
            }
            QPushButton:hover {
                background: rgba(255,255,255,0.14);
                border-color: rgba(255,255,255,0.2);
                color: white;
            }
        """)
        btn.clicked.connect(self.logout_clicked)
        return btn


class LeafMark(QWidget):
    def __init__(self):
        super().__init__()
        self.setFixedSize(26, 26)
        self.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground)

    def paintEvent(self, e):
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)

        path1 = QPainterPath()
        path1.moveTo(13, 2)
        path1.cubicTo(13, 2, 24, 8, 24, 15)
        path1.cubicTo(24, 22, 13, 26, 13, 26)
        path1.cubicTo(13, 26, 20, 20, 20, 15)
        path1.cubicTo(20, 10, 13, 2, 13, 2)
        p.fillPath(path1, QColor(255, 255, 255, 242))

        path2 = QPainterPath()
        path2.moveTo(20, 7)
        path2.cubicTo(20, 7, 26, 12, 25, 18)
        path2.cubicTo(24, 22, 20, 25, 20, 25)
        path2.cubicTo(20, 25, 25, 19, 25, 15)
        path2.cubicTo(25, 11, 20, 7, 20, 7)
        p.fillPath(path2, QColor(255, 255, 255, 115))


class GridMark(QWidget):
    def __init__(self):
        super().__init__()
        self.setFixedSize(30, 30)
        self.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground)

    def paintEvent(self, e):
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)
        bg = QPainterPath()
        bg.addRoundedRect(0, 0, 30, 30, 8, 8)
        p.fillPath(bg, QColor(255, 255, 255, 38))
        p.setPen(QPen(QColor(255, 255, 255, 64), 1))
        p.drawPath(bg)

        # draw 2×2 grid of squares
        p.setPen(Qt.PenStyle.NoPen)
        p.setBrush(QColor(255, 255, 255, 210))
        for rx, ry, rw, rh in [
            (6, 6, 7, 7), (17, 6, 7, 7),
            (17, 17, 7, 7), (6, 14, 7, 3), (6, 20, 7, 4),
        ]:
            p.drawRoundedRect(rx, ry, rw, rh, 1.5, 1.5)


# ─── STAT CARD ──────────────────────────────────────────────────────────────
class StatCard(QWidget):
    ACCENTS = {
        "red":   (C["red"],   C["red_light"]),
        "blue":  (C["blue"],  C["blue_light"]),
        "green": (C["green"], C["green_light"]),
    }

    def __init__(self, value, label_text, accent="red", icon_text="👤", parent=None):
        super().__init__(parent)
        self.accent_col, self.accent_bg = self.ACCENTS[accent]
        self.value_text = str(value)
        self.label_text = label_text
        self.icon_text  = icon_text
        self.setMinimumHeight(110)
        self.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Preferred)
        self.setAttribute(Qt.WidgetAttribute.WA_StyledBackground, True)
        self._build()
        shadow(self, blur=20, offset=(0, 4), color=(28, 20, 16, 14))

    def paintEvent(self, e):
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)

        # white card
        path = QPainterPath()
        path.addRoundedRect(0, 0, self.width(), self.height(), 18, 18)
        p.fillPath(path, QColor(C["white"]))
        p.setPen(QPen(QColor(C["border"]), 1))
        p.drawPath(path)

        # left accent bar
        acc = QPainterPath()
        acc.addRoundedRect(0, 16, 3, self.height()-32, 1.5, 1.5)
        p.fillPath(acc, QColor(self.accent_col))

        # ghost number
        p.setOpacity(0.05)
        gf = QFont("Georgia", 62, QFont.Weight.Bold)
        p.setFont(gf)
        p.setPen(QColor(self.accent_col))
        p.drawText(
            QRect(self.width()-80, -10, 90, self.height()+20),
            Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter,
            self.value_text
        )
        p.setOpacity(1.0)

    def _build(self):
        lay = QHBoxLayout(self)
        lay.setContentsMargins(22, 20, 22, 20)
        lay.setSpacing(16)

        # icon circle
        icon_w = QLabel(self.icon_text)
        icon_w.setFixedSize(52, 52)
        icon_w.setAlignment(Qt.AlignmentFlag.AlignCenter)
        icon_w.setFont(QFont("Segoe UI Emoji", 22))
        icon_w.setStyleSheet(
            f"background: {self.accent_bg}; border-radius: 14px;"
        )
        lay.addWidget(icon_w)

        # text
        text_col = QVBoxLayout()
        text_col.setSpacing(4)
        text_col.setContentsMargins(0, 0, 0, 0)

        val = QLabel(self.value_text)
        vf = QFont("Georgia", 28, QFont.Weight.Bold)
        val.setFont(vf)
        val.setStyleSheet(f"color: {self.accent_col}; background: transparent;")

        lbl = QLabel(self.label_text)
        lf = QFont("Segoe UI", 12)
        lbl.setFont(lf)
        lbl.setStyleSheet(f"color: {C['text3']}; background: transparent;")

        text_col.addWidget(val)
        text_col.addWidget(lbl)
        lay.addLayout(text_col)
        lay.addStretch()


# ─── ACTION CARD ────────────────────────────────────────────────────────────
class ActionCard(QWidget):
    clicked = pyqtSignal(str)
    ACCENTS = {
        "red":   (C["red"],   C["red_light"]),
        "blue":  (C["blue"],  C["blue_light"]),
        "green": (C["green"], C["green_light"]),
        "amber": (C["amber"], C["amber_light"]),
    }

    def __init__(self, label_text, icon_text, accent="red", parent=None):
        super().__init__(parent)
        self.label_text = label_text
        self.icon_text  = icon_text
        self.accent_col, self.accent_bg = self.ACCENTS[accent]
        self._hovered = False
        self.setMinimumHeight(120)
        self.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Preferred)
        self.setCursor(QCursor(Qt.CursorShape.PointingHandCursor))
        self.setAttribute(Qt.WidgetAttribute.WA_StyledBackground, True)
        self._build()
        shadow(self, blur=8, offset=(0, 2), color=(28, 20, 16, 10))

    def enterEvent(self, e):
        self._hovered = True
        self.update()

    def leaveEvent(self, e):
        self._hovered = False
        self.update()

    def mousePressEvent(self, e):
        self.clicked.emit(self.label_text)

    def paintEvent(self, e):
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)

        path = QPainterPath()
        path.addRoundedRect(0, 0, self.width(), self.height(), 18, 18)
        p.fillPath(path, QColor(C["white"]))

        border_col = QColor(self.accent_col) if self._hovered else QColor(C["border"])
        border_col.setAlpha(255 if self._hovered else 180)
        pen = QPen(border_col, 1.5 if self._hovered else 1)
        p.setPen(pen)
        p.drawPath(path)

        # bottom accent bar on hover
        if self._hovered:
            bar = QPainterPath()
            bar.addRoundedRect(18, self.height()-3, self.width()-36, 3, 1.5, 1.5)
            p.fillPath(bar, QColor(self.accent_col))

    def _build(self):
        lay = QVBoxLayout(self)
        lay.setContentsMargins(20, 22, 20, 22)
        lay.setAlignment(Qt.AlignmentFlag.AlignCenter)
        lay.setSpacing(12)

        icon_w = QLabel(self.icon_text)
        icon_w.setFixedSize(56, 56)
        icon_w.setAlignment(Qt.AlignmentFlag.AlignCenter)
        icon_w.setFont(QFont("Segoe UI Emoji", 24))
        icon_w.setStyleSheet(
            f"background: {self.accent_bg}; border-radius: 16px;"
        )
        icon_w.setAlignment(Qt.AlignmentFlag.AlignCenter)

        lbl = QLabel(self.label_text)
        lf = QFont("Segoe UI", 12, QFont.Weight.DemiBold)
        lbl.setFont(lf)
        lbl.setStyleSheet(f"color: {C['text']}; background: transparent;")
        lbl.setAlignment(Qt.AlignmentFlag.AlignCenter)

        lay.addWidget(icon_w, alignment=Qt.AlignmentFlag.AlignCenter)
        lay.addWidget(lbl, alignment=Qt.AlignmentFlag.AlignCenter)


# ─── VISIT ROW ──────────────────────────────────────────────────────────────
class VisitRow(QWidget):
    open_clicked = pyqtSignal(str)
    STATUS_STYLES = {
        "Review":  (C["red"],   C["red_light"],   "#B91C1C33"),
        "Active":  (C["green"], C["green_light"],  "#15803D33"),
        "Pending": (C["amber"], C["amber_light"],  "#B4530933"),
    }

    def __init__(self, name, tags, status, date, parent=None):
        super().__init__(parent)
        self.name   = name
        self.tags   = tags
        self.status = status
        self.date   = date
        self._hovered = False
        self.setMinimumHeight(72)
        self.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Preferred)
        self.setCursor(QCursor(Qt.CursorShape.PointingHandCursor))
        self.setAttribute(Qt.WidgetAttribute.WA_StyledBackground, True)
        self._build()
        shadow(self, blur=6, offset=(0, 1), color=(28, 20, 16, 8))

    def enterEvent(self, e):
        self._hovered = True
        self.update()

    def leaveEvent(self, e):
        self._hovered = False
        self.update()

    def paintEvent(self, e):
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)

        path = QPainterPath()
        path.addRoundedRect(0, 0, self.width(), self.height(), 12, 12)
        p.fillPath(path, QColor(C["white"]))
        p.setPen(QPen(QColor(C["border2"] if self._hovered else C["border"]), 1))
        p.drawPath(path)

        # left accent on hover
        col_str = self.STATUS_STYLES[self.status][0]
        if self._hovered:
            bar = QPainterPath()
            bar.addRoundedRect(0, 0, 3, self.height(), 1.5, 1.5)
            p.fillPath(bar, QColor(col_str))

    def _build(self):
        lay = QHBoxLayout(self)
        lay.setContentsMargins(20, 12, 16, 12)
        lay.setSpacing(14)

        # Avatar
        init = self.name[0].upper() if self.name and self.name[0].isalpha() else "—"
        av = QLabel(init)
        av.setFixedSize(44, 44)
        av.setAlignment(Qt.AlignmentFlag.AlignCenter)
        af = QFont("Georgia", 15, QFont.Weight.Bold)
        av.setFont(af)
        av.setStyleSheet(
            f"background: {C['bg2']}; color: {C['text2']}; "
            f"border-radius: 11px; border: 1.5px solid {C['border']};"
        )

        # Info column
        info = QVBoxLayout()
        info.setSpacing(5)
        info.setContentsMargins(0, 0, 0, 0)

        name_lbl = QLabel(self.name)
        nf = QFont("Segoe UI", 13, QFont.Weight.DemiBold)
        name_lbl.setFont(nf)
        name_lbl.setStyleSheet(f"color: {C['text']}; background: transparent;")

        # tags row
        tags_row = QHBoxLayout()
        tags_row.setSpacing(6)
        tags_row.setContentsMargins(0, 0, 0, 0)
        for i, tag in enumerate(self.tags):
            t = QLabel(tag)
            tf = QFont("Courier New", 10)
            t.setFont(tf)
            t.setStyleSheet(
                f"color: {C['text3']}; background: {C['bg2']}; "
                f"border: 1px solid {C['border']}; border-radius: 5px; "
                f"padding: 1px 7px;"
            )
            tags_row.addWidget(t)
            if i < len(self.tags)-1:
                dot = QLabel("·")
                dot.setStyleSheet(f"color: {C['border2']}; background: transparent;")
                tags_row.addWidget(dot)
        tags_row.addStretch()

        info.addWidget(name_lbl)
        info.addLayout(tags_row)

        # Right side
        right = QHBoxLayout()
        right.setSpacing(14)
        right.setContentsMargins(0, 0, 0, 0)
        right.setAlignment(Qt.AlignmentFlag.AlignVCenter)

        # Status badge
        st_col, st_bg, _ = self.STATUS_STYLES[self.status]
        status_lbl = QLabel(self.status)
        sf = QFont("Courier New", 10, QFont.Weight.Bold)
        status_lbl.setFont(sf)
        status_lbl.setFixedHeight(22)
        status_lbl.setStyleSheet(
            f"color: {st_col}; background: {st_bg}; border-radius: 10px; "
            f"border: 1px solid {st_col}44; padding: 0 10px;"
        )
        status_lbl.setAlignment(Qt.AlignmentFlag.AlignCenter)

        date_lbl = QLabel(self.date)
        df = QFont("Courier New", 10)
        date_lbl.setFont(df)
        date_lbl.setStyleSheet(f"color: {C['text3']}; background: transparent;")

        open_btn = QPushButton("Open  →")
        of = QFont("Segoe UI", 11, QFont.Weight.DemiBold)
        open_btn.setFont(of)
        open_btn.setFixedSize(88, 32)
        open_btn.setCursor(QCursor(Qt.CursorShape.PointingHandCursor))
        open_btn.setStyleSheet(f"""
            QPushButton {{
                background: {C['red']};
                color: white;
                border: none;
                border-radius: 9px;
            }}
            QPushButton:hover {{
                background: {C['red_dark']};
            }}
            QPushButton:pressed {{
                background: #7F1D1D;
            }}
        """)
        open_btn.clicked.connect(lambda: self.open_clicked.emit(self.name))

        right.addWidget(status_lbl)
        right.addWidget(date_lbl)
        right.addWidget(open_btn)

        lay.addWidget(av)
        lay.addLayout(info, 1)
        lay.addLayout(right)


# ─── ACTIVITY ROW ───────────────────────────────────────────────────────────
class ActivityItem(QWidget):
    COLORS = {
        "red":   (C["red"],   C["red_light"]),
        "blue":  (C["blue"],  C["blue_light"]),
        "green": (C["green"], C["green_light"]),
        "amber": (C["amber"], C["amber_light"]),
    }

    def __init__(self, icon, title, sub, time_str, accent="red", parent=None):
        super().__init__(parent)
        self.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground)
        self._build(icon, title, sub, time_str, accent)

    def _build(self, icon, title, sub, time_str, accent):
        col, bg = self.COLORS[accent]
        lay = QHBoxLayout(self)
        lay.setContentsMargins(0, 8, 0, 8)
        lay.setSpacing(12)

        dot = QLabel(icon)
        dot.setFixedSize(34, 34)
        dot.setAlignment(Qt.AlignmentFlag.AlignCenter)
        dot.setFont(QFont("Segoe UI Emoji", 14))
        dot.setStyleSheet(
            f"background: {bg}; border-radius: 9px; "
            f"border: 1px solid {col}33;"
        )

        body = QVBoxLayout()
        body.setSpacing(2)
        body.setContentsMargins(0, 0, 0, 0)

        t = QLabel(title)
        t.setFont(QFont("Segoe UI", 12, QFont.Weight.DemiBold))
        t.setStyleSheet(f"color: {C['text']}; background: transparent;")

        s = QLabel(sub)
        s.setFont(QFont("Segoe UI", 11))
        s.setStyleSheet(f"color: {C['text3']}; background: transparent;")

        body.addWidget(t)
        body.addWidget(s)

        time_lbl = QLabel(time_str)
        time_lbl.setFont(QFont("Courier New", 10))
        time_lbl.setStyleSheet(f"color: {C['text3']}; background: transparent;")
        time_lbl.setAlignment(Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter)

        lay.addWidget(dot)
        lay.addLayout(body, 1)
        lay.addWidget(time_lbl)


# ─── PANEL (card container) ──────────────────────────────────────────────────
class Panel(QWidget):
    def __init__(self, title, link_text="", parent=None):
        super().__init__(parent)
        self.setAttribute(Qt.WidgetAttribute.WA_StyledBackground, True)
        self._main = QVBoxLayout(self)
        self._main.setContentsMargins(0, 0, 0, 0)
        self._main.setSpacing(0)

        # header
        hdr = QWidget()
        hdr.setStyleSheet(
            f"background: {C['white']}; border-bottom: 1px solid {C['border']};"
            f"border-top-left-radius: 16px; border-top-right-radius: 16px;"
        )
        hdr.setFixedHeight(50)
        hdr_lay = QHBoxLayout(hdr)
        hdr_lay.setContentsMargins(22, 0, 16, 0)

        title_lbl = QLabel(title)
        tf = QFont("Georgia", 13, QFont.Weight.Bold)
        title_lbl.setFont(tf)
        title_lbl.setStyleSheet(f"color: {C['text']}; background: transparent; border: none;")
        hdr_lay.addWidget(title_lbl)
        hdr_lay.addStretch()

        if link_text:
            link = QLabel(link_text)
            lf = QFont("Courier New", 10)
            link.setFont(lf)
            link.setStyleSheet(
                f"color: {C['text3']}; background: transparent; border: none;"
                f"padding: 4px 10px;"
            )
            hdr_lay.addWidget(link)

        self._main.addWidget(hdr)

        # body container
        self._body = QWidget()
        self._body.setStyleSheet(
            f"background: {C['white']}; border-bottom-left-radius: 16px; border-bottom-right-radius: 16px;"
        )
        self._body_lay = QVBoxLayout(self._body)
        self._body_lay.setContentsMargins(22, 16, 22, 18)
        self._body_lay.setSpacing(0)
        self._main.addWidget(self._body)

        shadow(self, blur=20, offset=(0, 4), color=(28, 20, 16, 12))

    def paintEvent(self, e):
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)
        path = QPainterPath()
        path.addRoundedRect(0, 0, self.width(), self.height(), 16, 16)
        p.fillPath(path, QColor(C["white"]))
        p.setPen(QPen(QColor(C["border"]), 1))
        p.drawPath(path)

    def body(self):
        return self._body_lay


# ─── SECTION HEADER ─────────────────────────────────────────────────────────
class SectionHeader(QWidget):
    def __init__(self, title, link_text="", parent=None):
        super().__init__(parent)
        self.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground)
        lay = QHBoxLayout(self)
        lay.setContentsMargins(0, 0, 0, 0)

        # title + red dash
        title_row = QHBoxLayout()
        title_row.setSpacing(10)

        t = QLabel(title)
        tf = QFont("Georgia", 16, QFont.Weight.Bold)
        t.setFont(tf)
        t.setStyleSheet(f"color: {C['text']}; background: transparent;")
        title_row.addWidget(t)

        dash = QWidget()
        dash.setFixedSize(28, 2)
        dash.setStyleSheet(f"background: {C['red']}; border-radius: 1px;")
        title_row.addWidget(dash, alignment=Qt.AlignmentFlag.AlignVCenter)
        title_row.addStretch()
        lay.addLayout(title_row)

        if link_text:
            link = QLabel(link_text)
            lf = QFont("Courier New", 10)
            link.setFont(lf)
            link.setCursor(QCursor(Qt.CursorShape.PointingHandCursor))
            link.setStyleSheet(
                f"color: {C['text3']}; background: {C['white']}; "
                f"border: 1px solid {C['border']}; border-radius: 7px; "
                f"padding: 4px 12px;"
            )
            lay.addWidget(link)


# ─── DATE PILL ───────────────────────────────────────────────────────────────
class DatePill(QWidget):
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground)
        self.lbl = QLabel()
        self.lbl.setFont(QFont("Courier New", 11, QFont.Weight.Medium))
        self.lbl.setStyleSheet(f"color: {C['text2']}; background: transparent;")
        self._update()

        lay = QHBoxLayout(self)
        lay.setContentsMargins(0, 0, 0, 0)

        pill = QWidget()
        pill.setStyleSheet(
            f"background: {C['white']}; border: 1px solid {C['border']}; "
            f"border-radius: 20px;"
        )
        pill_lay = QHBoxLayout(pill)
        pill_lay.setContentsMargins(14, 6, 16, 6)
        pill_lay.setSpacing(8)

        dot = QWidget()
        dot.setFixedSize(8, 8)
        dot.setStyleSheet(f"background: {C['green']}; border-radius: 4px;")

        pill_lay.addWidget(dot)
        pill_lay.addWidget(self.lbl)
        lay.addWidget(pill)
        shadow(pill, blur=6, offset=(0, 1), color=(28, 20, 16, 8))

    def _update(self):
        now = datetime.now()
        self.lbl.setText(now.strftime("%A, %d %B %Y"))


# ─── MAIN WINDOW ────────────────────────────────────────────────────────────
class Dashboard(QMainWindow):
    def __init__(self):
        super().__init__()
        self.setWindowTitle("Pixel Pro — Dashboard")
        self.resize(1280, 820)
        self.setMinimumSize(1024, 700)
        self._build()

    def _build(self):
        central = QWidget()
        self.setCentralWidget(central)
        root = QVBoxLayout(central)
        root.setContentsMargins(0, 0, 0, 0)
        root.setSpacing(0)

        # Background
        central.setStyleSheet(f"background: {C['bg']};")

        # Topbar
        topbar = TopBar("vansh")
        topbar.logout_clicked.connect(self._on_logout)
        root.addWidget(topbar)

        # Scrollable content
        scroll = QScrollArea()
        scroll.setWidgetResizable(True)
        scroll.setFrameShape(QFrame.Shape.NoFrame)
        scroll.setStyleSheet("background: transparent; border: none;")
        scroll.setHorizontalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAlwaysOff)

        content = QWidget()
        content.setStyleSheet(f"background: transparent;")
        cv = QVBoxLayout(content)
        cv.setContentsMargins(40, 36, 40, 48)
        cv.setSpacing(0)

        # ── Greeting row
        greet_row = QHBoxLayout()
        greet_row.setContentsMargins(0, 0, 0, 32)

        greet_col = QVBoxLayout()
        greet_col.setSpacing(0)

        greet = QLabel()
        greet.setText(
            f'<span style="font-family: Georgia; font-size: 26px; '
            f'font-weight: bold; color: {C["text"]};">'
            f'Good day, <a href="#" style="color: {C["red"]}; text-decoration: none;">vansh</a>'
            f' 👋</span>'
        )
        greet.setOpenExternalLinks(False)
        greet.setTextFormat(Qt.TextFormat.RichText)
        greet.setTextInteractionFlags(Qt.TextInteractionFlag.TextBrowserInteraction)
        greet_col.addWidget(greet)

        greet_row.addLayout(greet_col)
        greet_row.addStretch()

        date_pill = DatePill()
        greet_row.addWidget(date_pill, alignment=Qt.AlignmentFlag.AlignVCenter)

        cv.addLayout(greet_row)

        # ── Stats
        stats_row = QHBoxLayout()
        stats_row.setSpacing(16)
        stats_row.setContentsMargins(0, 0, 0, 32)

        stats_row.addWidget(StatCard(1,  "Total Patients", "red",   "👥"))
        stats_row.addWidget(StatCard(5,  "Total Visits",   "blue",  "📅"))
        stats_row.addWidget(StatCard(3,  "Today's Visits", "green", "🗓️"))
        cv.addLayout(stats_row)

        # ── Quick Actions
        qa_hdr = SectionHeader("Quick Actions")
        cv.addWidget(qa_hdr)
        cv.addSpacing(16)

        qa_grid = QHBoxLayout()
        qa_grid.setSpacing(14)

        for label_t, icon, accent in [
            ("New Patient",    "➕", "red"),
            ("Search Patient", "🔍", "blue"),
            ("All Patients",   "👥", "green"),
            ("PACS Settings",  "⚙️", "amber"),
        ]:
            card = ActionCard(label_t, icon, accent)
            qa_grid.addWidget(card)

        cv.addLayout(qa_grid)
        cv.addSpacing(32)

        # ── Recent Visits
        rv_hdr = SectionHeader("Recent Visits", "View all →")
        cv.addWidget(rv_hdr)
        cv.addSpacing(16)

        visits_data = [
            ("wretyuio dffgujkl", ["PT-0001", "VS-0005", "Dr. 12qwertyuiop"], "Review",  "11 Mar 2026"),
            ("wretyuio dffgujkl", ["PT-0001", "VS-0004", "Dr. VANSH"],        "Active",  "11 Mar 2026"),
            ("— (Unknown Patient)", ["VS-0003", "Dr. aman"],                  "Pending", "11 Mar 2026"),
        ]

        visits_col = QVBoxLayout()
        visits_col.setSpacing(10)
        for name, tags, status, date in visits_data:
            row = VisitRow(name, tags, status, date)
            visits_col.addWidget(row)

        cv.addLayout(visits_col)
        cv.addSpacing(32)

        # ── Activity Log
        act_panel = Panel("Activity Log", "Today")

        act_body = act_panel.body()
        act_body.setContentsMargins(22, 12, 22, 18)

        activities = [
            ("▶️",  "Session started",     "Demo Testing · Camera 1080p",   "6:51 PM", "red"),
            ("🖼️", "Image captured",       "Frame #0024 · PT-0001",         "6:49 PM", "blue"),
            ("➕",  "Patient registered",  "wretyuio dffgujkl · PT-0001",   "6:30 PM", "green"),
            ("📄",  "Visit report created","VS-0003 · Dr. aman",             "3:15 PM", "amber"),
        ]

        # 2-column grid for activities
        act_grid = QGridLayout()
        act_grid.setSpacing(0)
        act_grid.setHorizontalSpacing(32)

        for i, (icon, title, sub, t, accent) in enumerate(activities):
            row = i // 2
            col = i % 2
            item = ActivityItem(icon, title, sub, t, accent)

            # separator line between items in same column
            if i >= 2:
                line = QFrame()
                line.setFrameShape(QFrame.Shape.HLine)
                line.setStyleSheet(f"color: {C['border']}; background: {C['border']};")
                line.setFixedHeight(1)
                act_grid.addWidget(line, row*2-1, col)

            act_grid.addWidget(item, row*2, col)

        act_body.addLayout(act_grid)
        cv.addWidget(act_panel)

        cv.addStretch()
        scroll.setWidget(content)
        root.addWidget(scroll)

    def _on_logout(self):
        self.close()


# ─── ENTRY ───────────────────────────────────────────────────────────────────
if __name__ == "__main__":
    app = QApplication(sys.argv)
    app.setStyle("Fusion")

    # smooth font rendering
    from PyQt6.QtGui import QFont
    app.setFont(QFont("Segoe UI", 11))

    win = Dashboard()
    win.show()
    sys.exit(app.exec())
